import React, { useState, useEffect } from 'react';

// Background farm images (Unsplash - free to use)
const bgImages = [
  'https://images.unsplash.com/photo-1500382017468-9049fed747ef?w=1600&q=80', // golden farm field
  'https://images.unsplash.com/photo-1464226184884-fa280b87c399?w=1600&q=80', // green farm
  'https://images.unsplash.com/photo-1523741543316-beb7fc7023d8?w=1600&q=80', // farm at sunset
];

// Produce slider images
const produceSlides = [
  { url: 'https://images.unsplash.com/photo-1540148426945-6cf22a6b2383?w=400&q=80', label: 'Fresh Tomatoes' },
  { url: 'https://images.unsplash.com/photo-1574316071802-0d684efa7bf5?w=400&q=80', label: 'Sweet Mangoes' },
  { url: 'https://images.unsplash.com/photo-1611735341450-74d61e660ad2?w=400&q=80', label: 'Green Broccoli' },
  { url: 'https://images.unsplash.com/photo-1550828520-4cb496926fc9?w=400&q=80', label: 'Red Apples' },
  { url: 'https://images.unsplash.com/photo-1518977676601-b53f82aba655?w=400&q=80', label: 'Golden Potatoes' },
  { url: 'https://images.unsplash.com/photo-1587334207104-8c7583d7e83e?w=400&q=80', label: 'Fresh Grapes' },
  { url: 'https://images.unsplash.com/photo-1598170845058-32b9d6a5da37?w=400&q=80', label: 'Carrots' },
  { url: 'https://images.unsplash.com/photo-1589927986089-35812388d1f4?w=400&q=80', label: 'Bananas' },
];

function Login({ onLogin }) {
  const [view, setView] = useState('landing');
  const [role, setRole] = useState('buyer');
  const [animating, setAnimating] = useState(false);
  const [slideDir, setSlideDir] = useState('right');

  // Background image cycling
  const [bgIndex, setBgIndex] = useState(0);
  const [bgFade, setBgFade] = useState(true);

  // Produce slider
  const [produceIndex, setProduceIndex] = useState(0);

  // Login fields
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Signup fields - buyer
  const [buyerName, setBuyerName] = useState('');
  const [buyerLocation, setBuyerLocation] = useState('');
  const [buyerInterest, setBuyerInterest] = useState('');

  // Signup fields - seller
  const [sellerName, setSellerName] = useState('');
  const [sellerLocation, setSellerLocation] = useState('');
  const [sellerAadhar, setSellerAadhar] = useState('');
  const [sellerFile, setSellerFile] = useState(null);

  const [signupError, setSignupError] = useState('');

  // Auto-cycle background
  useEffect(() => {
    const interval = setInterval(() => {
      setBgFade(false);
      setTimeout(() => {
        setBgIndex(i => (i + 1) % bgImages.length);
        setBgFade(true);
      }, 600);
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  // Auto-advance produce slider
  useEffect(() => {
    const interval = setInterval(() => {
      setProduceIndex(i => (i + 1) % (produceSlides.length - 3));
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  const navigate = (nextView, dir = 'left') => {
    if (animating) return;
    setLoginError('');
    setSignupError('');
    setAnimating(true);
    setSlideDir(dir);
    setTimeout(() => {
      setView(nextView);
      setAnimating(false);
    }, 400);
  };

  const handleLogin = () => {
    if (!loginEmail.trim() || !loginPassword.trim()) {
      setLoginError('⚠️ Please fill in both email and password.');
      return;
    }
    onLogin({ role: 'user' });
  };

  const handleSignup = () => {
    if (role === 'buyer') {
      if (!buyerName.trim() || !buyerLocation.trim()) {
        setSignupError('⚠️ Please fill in your name and location.');
        return;
      }
    } else {
      if (!sellerName.trim() || !sellerLocation.trim() || !sellerAadhar.trim()) {
        setSignupError('⚠️ Please fill in all required fields.');
        return;
      }
      if (!sellerFile) {
        setSignupError('⚠️ Please upload your income proof.');
        return;
      }
    }
    onLogin({ role });
  };

  const handleRoleSwitch = (newRole) => {
    setSignupError('');
    setRole(newRole);
  };

  const trackTranslate = role === 'buyer' ? '0%' : '-50%';

  const visibleSlides = produceSlides.slice(produceIndex, produceIndex + 4);

  return (
    <div className="portal-root">

      {/* ── REAL BACKGROUND IMAGE ── */}
      <div
        className={`real-bg ${bgFade ? 'bg-visible' : 'bg-hidden'}`}
        style={{ backgroundImage: `url(${bgImages[bgIndex]})` }}
      />
      <div className="bg-overlay" />

      {/* ── NAVBAR ── */}
      <nav className="top-nav">
        <div className="nav-brand">
          <span className="brand-leaf">🌿</span>
          <span className="brand-text">AGRI<span className="brand-accent">-AI</span></span>
        </div>
        <div className="nav-links">
          <span>Home</span>
          <span>About Us</span>
          <span>Communities</span>
          <span>Contacts</span>
          <span className="nav-help">Help</span>
        </div>
      </nav>

      {/* ── MAIN LAYOUT ── */}
      <div className="main-layout">

        {/* LEFT: Auth Card */}
        <div className="auth-side">
          <div className="glass-card">
            <div
              className={`slide-container ${animating ? `exit-${slideDir}` : 'enter'}`}
              key={view}
            >
              {/* LANDING */}
              {view === 'landing' && (
                <div className="view-panel">
                  <div className="portal-icon">
                    <div className="icon-ring"><span>🌾</span></div>
                  </div>
                  <h1 className="portal-title">Online Farm<br />Portal</h1>
                  <p className="portal-sub">Connect. Trade. Grow.</p>
                  <div className="landing-btns">
                    <button className="btn-agri" onClick={() => navigate('login', 'left')}>
                      <span className="btn-icon">🔑</span> Login
                    </button>
                    <button className="btn-agri btn-secondary" onClick={() => navigate('signup', 'left')}>
                      <span className="btn-icon">🌱</span> Sign Up
                    </button>
                  </div>
                </div>
              )}

              {/* LOGIN */}
              {view === 'login' && (
                <div className="view-panel">
                  <div className="portal-icon small">
                    <div className="icon-ring"><span>🔒</span></div>
                  </div>
                  <h2 className="panel-title">Secure Login</h2>
                  <p className="panel-sub">Welcome back, farmer</p>
                  <div className="input-group">
                    <span className="input-icon">👤</span>
                    <input
                      type="text"
                      className={`agri-input ${loginError && !loginEmail.trim() ? 'input-error' : ''}`}
                      placeholder="Email / Mobile *"
                      value={loginEmail}
                      onChange={e => { setLoginEmail(e.target.value); setLoginError(''); }}
                    />
                  </div>
                  <div className="input-group">
                    <span className="input-icon">🔐</span>
                    <input
                      type="password"
                      className={`agri-input ${loginError && !loginPassword.trim() ? 'input-error' : ''}`}
                      placeholder="Password *"
                      value={loginPassword}
                      onChange={e => { setLoginPassword(e.target.value); setLoginError(''); }}
                    />
                  </div>
                  {loginError && <p className="error-msg">{loginError}</p>}
                  <a className="forgot-link">Forgot Password?</a>
                  <button className="btn-agri full-w mt-20" onClick={handleLogin}>
                    Access Dashboard →
                  </button>
                  <button className="btn-back" onClick={() => navigate('landing', 'right')}>← Back</button>
                </div>
              )}

              {/* SIGNUP */}
              {view === 'signup' && (
                <div className="view-panel">
                  <h2 className="panel-title">Join the Network</h2>
                  <div className="role-toggle-wrap">
                    <div className="role-slider" style={{ left: role === 'buyer' ? '4px' : 'calc(50%)' }}></div>
                    <button className={`role-btn ${role === 'buyer' ? 'active' : ''}`} onClick={() => handleRoleSwitch('buyer')}>🛒 Buyer</button>
                    <button className={`role-btn ${role === 'seller' ? 'active' : ''}`} onClick={() => handleRoleSwitch('seller')}>🚜 Seller</button>
                  </div>
                  <div className="role-forms-viewport">
                    <div className="role-forms-track" style={{ transform: `translateX(${trackTranslate})` }}>
                      {/* Buyer */}
                      <div className="role-form-panel">
                        <div className="input-group">
                          <span className="input-icon">👤</span>
                          <input type="text" className={`agri-input ${signupError && role==='buyer' && !buyerName.trim() ? 'input-error':''}`} placeholder="Full Name *" value={buyerName} onChange={e=>{setBuyerName(e.target.value);setSignupError('');}} />
                        </div>
                        <div className="input-group">
                          <span className="input-icon">📍</span>
                          <input type="text" className={`agri-input ${signupError && role==='buyer' && !buyerLocation.trim() ? 'input-error':''}`} placeholder="Location *" value={buyerLocation} onChange={e=>{setBuyerLocation(e.target.value);setSignupError('');}} />
                        </div>
                        <select className="agri-select" value={buyerInterest} onChange={e=>setBuyerInterest(e.target.value)}>
                          <option value="">Select Primary Interest</option>
                          <option>🥦 Vegetables</option>
                          <option>🍎 Fruits</option>
                          <option>🌾 Grains</option>
                        </select>
                      </div>
                      {/* Seller */}
                      <div className="role-form-panel">
                        <div className="input-group">
                          <span className="input-icon">👤</span>
                          <input type="text" className={`agri-input ${signupError && role==='seller' && !sellerName.trim() ? 'input-error':''}`} placeholder="Full Name *" value={sellerName} onChange={e=>{setSellerName(e.target.value);setSignupError('');}} />
                        </div>
                        <div className="input-group">
                          <span className="input-icon">📍</span>
                          <input type="text" className={`agri-input ${signupError && role==='seller' && !sellerLocation.trim() ? 'input-error':''}`} placeholder="Location *" value={sellerLocation} onChange={e=>{setSellerLocation(e.target.value);setSignupError('');}} />
                        </div>
                        <div className="input-group">
                          <span className="input-icon">🪪</span>
                          <input type="text" className={`agri-input ${signupError && role==='seller' && !sellerAadhar.trim() ? 'input-error':''}`} placeholder="Aadhar / PAN No. *" value={sellerAadhar} onChange={e=>{setSellerAadhar(e.target.value);setSignupError('');}} />
                        </div>
                        <div className={`file-input-wrap ${signupError && role==='seller' && !sellerFile ? 'file-error':''}`}>
                          <label className="file-label">📄 Income Proof *</label>
                          <input type="file" className="file-input" onChange={e=>{setSellerFile(e.target.files[0]);setSignupError('');}} />
                        </div>
                      </div>
                    </div>
                  </div>
                  {signupError && <p className="error-msg">{signupError}</p>}
                  <button className="btn-agri full-w mt-10" onClick={handleSignup}>Create Profile 🌱</button>
                  <button className="btn-back" onClick={() => navigate('landing', 'right')}>← Cancel</button>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* RIGHT: Info + Produce Slider */}
        <div className="info-side">
          <div className="info-tagline">
            <h2 className="info-title">Farm Fresh,<br />Direct to You</h2>
            <p className="info-desc">Connect directly with farmers and buyers across India. Fresh produce, fair prices, zero middlemen.</p>
          </div>

          {/* Produce Slider */}
          <div className="produce-slider-wrap">
            <p className="slider-heading">🛒 Today's Fresh Produce</p>
            <div className="produce-track-outer">
              <button className="slider-arrow left" onClick={() => setProduceIndex(i => Math.max(0, i - 1))}>‹</button>
              <div className="produce-track">
                {visibleSlides.map((item, idx) => (
                  <div className="produce-card" key={produceIndex + idx}>
                    <img src={item.url} alt={item.label} className="produce-img" />
                    <span className="produce-label">{item.label}</span>
                  </div>
                ))}
              </div>
              <button className="slider-arrow right" onClick={() => setProduceIndex(i => Math.min(produceSlides.length - 4, i + 1))}>›</button>
            </div>
            {/* Dots */}
            <div className="slider-dots">
              {Array.from({ length: produceSlides.length - 3 }).map((_, i) => (
                <span
                  key={i}
                  className={`dot ${i === produceIndex ? 'dot-active' : ''}`}
                  onClick={() => setProduceIndex(i)}
                />
              ))}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}

export default Login;
